  }
}

totalPrice = roundPrice(calculatedUnitPrice * {{node:code_node_wBfvXM2G.data.baseQty}});

// Returns the post-deduction value for a field; only the matching category is deducted
const computeUpdated = (existing, field) => {
  const current = roundQty(existing[field] || 0);
  const deduct = field === categoryField ? deductQty : 0;
  return roundQty(current - deduct);
};

// Item Balance (always fetched upstream)
const existingBalance = {{node:get_node_uaq6Z1ej.data.data}} || {}
const unrestrictedQty = computeUpdated(existingBalance, "unrestricted_qty")
const reservedQty = computeUpdated(existingBalance, "reserved_qty")
const blockedQty = computeUpdated(existingBalance, "block_qty")
const qualityInspectionQty = computeUpdated(existingBalance, "qualityinsp_qty")
const inTransitQty = computeUpdated(existingBalance, "intransit_qty")
const balanceQty = roundQty(roundQty(existingBalance.balance_quantity || 0) - deductQty)

// Item Batch Balance (only when batch_id is provided)
