let batchReservedQty = 0
let batchBlockedQty = 0
let batchQualityInspectionQty = 0
let batchInTransitQty = 0
let batchBalanceQty = 0

if ({{workflowparams:batch_id}} && {{workflowparams:batch_id}} !== "") {
  const existingBatchBalance = {{node:get_node_GjRiq3dT.data.data}} || {}
  batchUnrestrictedQty = computeUpdated(existingBatchBalance, "unrestricted_qty")
  batchReservedQty = computeUpdated(existingBatchBalance, "reserved_qty")
  batchBlockedQty = computeUpdated(existingBatchBalance, "block_qty")
  batchQualityInspectionQty = computeUpdated(existingBatchBalance, "qualityinsp_qty")
  batchInTransitQty = computeUpdated(existingBatchBalance, "intransit_qty")
  batchBalanceQty = roundQty(roundQty(existingBatchBalance.balance_quantity || 0) - deductQty)
}

