// Helper function
const roundQty = (value) => parseFloat(parseFloat(value || 0).toFixed(3))

let remainingQty = roundQty(deductionQty)
const updates = []

for (let i = 0; i < sortedRecords.length; i++) {
  if (remainingQty <= 0) {
    // Stop processing, add remaining records unchanged
    break
  }

  const record = sortedRecords[i]
  const availableQty = roundQty(record.fifo_available_quantity || 0)

  if (availableQty <= 0) {
    // Skip this record
    continue
  }

  const qtyToDeduct = Math.min(remainingQty, availableQty)
  const newAvailableQty = roundQty(availableQty - qtyToDeduct)

  updates.push({
    id: record.id,
    fifo_available_quantity: parseFloat(newAvailableQty).toFixed(3),
    fifo_sequence: record.fifo_sequence,
    oldQty: availableQty,
    deducted: qtyToDeduct
  })

  remainingQty = roundQty(remainingQty - qtyToDeduct)
}

return {
  updates: updates,
  remainingQty: remainingQty
}

